CREATE OR REPLACE FUNCTION public._scoring_weight_overrides_is_valid(
  p_overrides jsonb
) RETURNS boolean
LANGUAGE sql
IMMUTABLE
PARALLEL SAFE
SET search_path = pg_catalog
